from typing import List

def generate(numRows: int) -> List[List[int]]:
    result: List[List[int]] = []

    for i in range(numRows):
        row = [1] * (i + 1)
        for j in range(1, i):
            row[j] = result[i - 1][j - 1] + result[i - 1][j]
        result.append(row)

    return result
